class Solution {
 public:
  int climbStairs(int n, vector<int>& costs)
  {
    if (n <= 1) return costs[0];
    int dp[n + 1];
    dp[0] = costs[0];
    for (int i = 1; i <= n; i++)
    {
      if (i <= 2)
      {
        dp[i] = costs[i - 1];
      }
      else
      {
        dp[i] = min(dp[i - 1], dp[i - 2]) + costs[i - 1];
      }
      if (dp[i] < dp[i - 3] + costs[i - 1])
      {
        dp[i] = dp[i - 3] + costs[i - 1];
      }
    }
    return dp[n];
  }
};

